import { validate, Schema } from '../src/schema';

describe('Schema Validator', () => {
  test('validates string type', () => {
    const schema: Schema = { type: 'string' };
    expect(validate('hello', schema).valid).toBe(true);
    expect(validate(42, schema).valid).toBe(false);
  });

  test('validates number with min/max', () => {
    const schema: Schema = { type: 'number', min: 0, max: 100 };
    expect(validate(50, schema).valid).toBe(true);
    expect(validate(-1, schema).valid).toBe(false);
    expect(validate(101, schema).valid).toBe(false);
  });

  test('validates string length', () => {
    const schema: Schema = { type: 'string', minLength: 2, maxLength: 10 };
    expect(validate('hi', schema).valid).toBe(true);
    expect(validate('a', schema).valid).toBe(false);
    expect(validate('a'.repeat(11), schema).valid).toBe(false);
  });

  test('validates object with required fields', () => {
    const schema: Schema = {
      type: 'object',
      properties: {
        name: { type: 'string', required: true },
        age: { type: 'number' },
      },
    };
    expect(validate({ name: 'Alice', age: 30 }, schema).valid).toBe(true);
    expect(validate({ age: 30 }, schema).valid).toBe(false); // missing required name
    expect(validate({ name: 'Bob' }, schema).valid).toBe(true); // age optional
  });

  test('returns error messages', () => {
    const schema: Schema = { type: 'number', min: 10 };
    const result = validate(5, schema);
    expect(result.valid).toBe(false);
    expect(result.errors.length).toBeGreaterThan(0);
  });
});

export interface Schema {
  type: 'string' | 'number' | 'boolean' | 'array' | 'object';
  required?: boolean;
  min?: number;
  max?: number;
  minLength?: number;
  maxLength?: number;
  properties?: Record<string, Schema>;
  items?: Schema;
}

export interface ValidationResult {
  valid: boolean;
  errors: string[];
}

export function validate(value: unknown, schema: Schema): ValidationResult {
  const errors: string[] = [];

  // Type check
  if (schema.type === 'string' && typeof value !== 'string') {
    errors.push(`expected string, got ${typeof value}`);
  }
  if (schema.type === 'number' && typeof value !== 'number') {
    errors.push(`expected number, got ${typeof value}`);
  }
  if (schema.type === 'boolean' && typeof value !== 'boolean') {
    errors.push(`expected boolean, got ${typeof value}`);
  }
  if (schema.type === 'array' && !Array.isArray(value)) {
    errors.push(`expected array, got ${typeof value}`);
  }
  if (schema.type === 'object' && (typeof value !== 'object' || value === null || Array.isArray(value))) {
    errors.push(`expected object, got ${typeof value}`);
  }

  if (errors.length > 0) return { valid: false, errors };

  // Number constraints
  if (schema.type === 'number' && typeof value === 'number') {
    if (schema.min !== undefined && value < schema.min) {
      errors.push(`value ${value} is below minimum ${schema.min}`);
    }
    if (schema.max !== undefined && value > schema.max) {
      errors.push(`value ${value} exceeds maximum ${schema.max}`);
    }
  }

  // String constraints
  if (schema.type === 'string' && typeof value === 'string') {
    if (schema.minLength !== undefined && value.length < schema.minLength) {
      errors.push(`string length ${value.length} below minimum ${schema.minLength}`);
    }
    if (schema.maxLength !== undefined && value.length > schema.maxLength) {
      errors.push(`string length ${value.length} exceeds maximum ${schema.maxLength}`);
    }
  }

  // Object properties
  if (schema.type === 'object' && schema.properties && typeof value === 'object' && value !== null) {
    const obj = value as Record<string, unknown>;
    for (const [key, propSchema] of Object.entries(schema.properties)) {
      if (propSchema.required && !(key in obj)) {
        errors.push(`missing required field: ${key}`);
        continue;
      }
      if (key in obj) {
        const propResult = validate(obj[key], propSchema);
        errors.push(...propResult.errors.map(e => `${key}: ${e}`));
      }
    }
  }

  return { valid: errors.length === 0, errors };
}
